  1→import { CodeFileLoader } from '@graphql-tools/code-file-loader'
  2→import { loadSchema } from '@graphql-tools/load'
  3→import type {
  4→  DocumentNode,
  5→  FieldNode,
  6→  InlineFragmentNode,
  7→  OperationDefinitionNode,
  8→  OperationTypeNode,
  9→} from 'graphql'
 10→import { Kind, parse, print, visit } from 'graphql'
 11→
 12→import { rootSchema } from '@redwoodjs/graphql-server'
 13→import { getPaths } from '@redwoodjs/project-config'
 14→
 15→interface Operation {
 16→  operation: OperationTypeNode
 17→  name: string | undefined
 18→  fields: (string | Field)[]
 19→}
 20→
 21→interface Field {
 22→  string: (string | Field)[]
 23→}
 24→
 25→export const parseGqlQueryToAst = (gqlQuery: string) => {
 26→  const ast = parse(gqlQuery)
 27→  return parseDocumentAST(ast)
 28→}
 29→
 30→export const parseDocumentAST = (document: DocumentNode) => {
 31→  const operations: Operation[] = []
 32→
 33→  visit(document, {
 34→    OperationDefinition(node: OperationDefinitionNode) {
 35→      const fields: any[] = []
 36→
 37→      node.selectionSet.selections.forEach((field) => {
 38→        fields.push(getFields(field as FieldNode))
 39→      })
 40→
 41→      operations.push({
 42→        operation: node.operation,
 43→        name: node.name?.value,
 44→        fields,
 45→      })
 46→    },
 47→  })
 48→
 49→  return operations
 50→}
 51→
 52→const getFields = (field: FieldNode): any => {
 53→  // base
 54→  if (!field.selectionSet) {
 55→    return field.name.value
 56→  } else {
 57→    const obj: Record<string, FieldNode[]> = {
 58→      [field.name.value]: [],
 59→    }
 60→
 61→    const lookAtFieldNode = (node: FieldNode | InlineFragmentNode): void => {
 62→      node.selectionSet?.selections.forEach((subField) => {
 63→        switch (subField.kind) {
 64→          case Kind.FIELD:
 65→            obj[field.name.value].push(getFields(subField))
 66→            break
 67→          case Kind.FRAGMENT_SPREAD:
 68→            // TODO: Maybe this will also be needed, right now it's accounted for to not crash in the tests
 69→            break
 70→          case Kind.INLINE_FRAGMENT:
 71→            lookAtFieldNode(subField)
 72→        }
 73→      })
 74→    }
 75→
 76→    lookAtFieldNode(field)
 77→
 78→    return obj
 79→  }
 80→}
 81→
 82→export const listQueryTypeFieldsInProject = async () => {
 83→  try {
 84→    const schemaPointerMap = {
 85→      [print(rootSchema.schema)]: {},
 86→      'graphql/**/*.sdl.{js,ts}': {},
 87→      'directives/**/*.{js,ts}': {},
 88→      'subscriptions/**/*.{js,ts}': {},
 89→    }
 90→
 91→    const mergedSchema = await loadSchema(schemaPointerMap, {
 92→      loaders: [
 93→        new CodeFileLoader({
 94→          noRequire: true,
 95→          pluckConfig: {
 96→            globalGqlIdentifierName: 'gql',
 97→          },
 98→        }),
 99→      ],
100→      cwd: getPaths().api.src,
101→      assumeValidSDL: true,
102→    })
103→
104→    const queryTypeFields = mergedSchema.getQueryType()?.getFields()
105→
106→    // Return empty array if no schema found
107→    return Object.keys(queryTypeFields ?? {})
108→  } catch (e) {
109→    console.error(e)
110→    return []
111→  }
112→}
113→

export const QUERY: TypedDocumentNode<
  ${operationName},
  ${operationName}Variables
> = gql`
  query ${operationName}($id: ${idType}!) {
    ${camelName}: ${camelName}(${idName}: $id) {
      ${idName}
    }
  }
`

export const Loading = () => <div>Loading...</div>

export const Empty = () => <div>Empty</div>

export const Failure = ({
  error,
}: CellFailureProps<${operationName}Variables>) => (
  <div style={{ color: 'red' }}>Error: {error?.message}</div>
)
